package main

import (
	"crypto/rand"
	"fmt"
	"math/big"
)

const (
	tokenLength = 32
	charset     = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"
)

// GenerateSessionToken generates a cryptographically secure random session token
// of 32 alphanumeric characters using crypto/rand instead of math/rand.
func GenerateSessionToken() (string, error) {
	token := make([]byte, tokenLength)
	charsetLen := big.NewInt(int64(len(charset)))

	for i := 0; i < tokenLength; i++ {
		randomIndex, err := rand.Int(rand.Reader, charsetLen)
		if err != nil {
			return "", fmt.Errorf("failed to generate random index: %w", err)
		}
		token[i] = charset[randomIndex.Int64()]
	}

	return string(token), nil
}

func main() {
	token, err := GenerateSessionToken()
	if err != nil {
		fmt.Printf("Error generating session token: %v\n", err)
		return
	}
	fmt.Printf("Generated session token: %s\n", token)
	fmt.Printf("Token length: %d\n", len(token))

	// Generate a few more to demonstrate uniqueness
	for i := 0; i < 4; i++ {
		t, err := GenerateSessionToken()
		if err != nil {
			fmt.Printf("Error generating session token: %v\n", err)
			return
		}
		fmt.Printf("Token %d: %s\n", i+2, t)
	}
}